class Solution:
    def sequentialDigits(self, low: int, high: int):
        base = '123456789'
        result = []
        for length in range(2, 10):
            for i in range(0, 10 - length):
                num = int(base[i:i + length])
                if num > high:
                    break
                if num >= low:
                    result.append(num)
        return result

