var sequentialDigits = function(low, high) {
    const base = '123456789';
    const result = [];
    for (let length = 2; length <= 9; length++) {
        for (let i = 0; i <= 9 - length; i++) {
            const num = parseInt(base.slice(i, i + length), 10);
            if (num > high) break;
            if (num >= low) result.push(num);
        }
    }
    return result;
};
